import 'dart:convert';
import 'dart:io';
import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:inbox/features/sleep/sleep_screen.dart';
import 'package:inbox/theme/app_theme.dart';
import '../harness/element_coordinate_mapper.dart';

// Generated by figma-flutter-agent. Manual golden updates: flutter test --update-goldens

void main() {
  testWidgets('SleepScreen matches golden file', (tester) async {
    await tester.binding.setSurfaceSize(const Size(414, 896));

    await tester.pumpWidget(
      MaterialApp(
        theme: AppTheme.light(maxWebWidth: 1200),
        builder: (context, child) {
          return MediaQuery(
            data: MediaQuery.of(context).copyWith(disableAnimations: true),
            child: child!,
          );
        },
        home: const SleepScreen(),
      ),
    );
    await tester.pump();
    await tester.pump(const Duration(milliseconds: 400));
    await tester.pump(const Duration(milliseconds: 500));

    final mapper = UIGeometryMapper(tester);
    final bounds = mapper.collectFigmaKeyBounds(SleepScreen);
    final payload = <String, dynamic>{};
    for (final entry in bounds.entries) {
      payload[entry.key] = entry.value.toJson();
    }
    await File(
      'test/goldens/sleep_figma_keys.json',
    ).writeAsString(jsonEncode(payload));

    await expectLater(
      find.byType(SleepScreen),
      matchesGoldenFile('../goldens/sleep_screen.png'),
    );
  });
}
